local LxBaseMgr = require("LApp.Manager.LxBaseMgr")
---@class LxMovieMgr:LxBaseMgr
local LxMovieMgr = classX("LxMovieMgr", LxBaseMgr)

local typeofRawImage = typeof(UnityEngine.UI.RawImage)

function LxMovieMgr:Initialize()
    LxBaseMgr.Initialize(self)

    local cameraTrans = FindObject("RehtGame/NodeMovie/MovieCamera").transform
    self._movieCamera = cameraTrans:GetComponent(typeof(UnityEngine.Camera))
    self._movieCamera.enabled = false

    local movieTrans = FindObject("RehtGame/NodeMovie").transform
    self._movieTrans = movieTrans

    self._movieId = 0

    ---@type table<number,LxVideo>
    self._videos = {}
    ---@type LxVideo
    self._cameraVideo = nil

    self._isVideoPlaying = false
end

function LxMovieMgr:MakeMovieId()
    local movieId = self._movieId
    movieId = movieId + 1
    self._movieId = movieId
    return movieId
end

function LxMovieMgr:Dispose()
    for k,v in pairs(self._videos) do
        v:Dispose()
    end
    LxBaseMgr.Dispose(self)
end

function LxMovieMgr:OnUpdate()
    if self._isDisposed then return end

    local ids = {}
    local isPlaying = false
    for k,v in pairs(self._videos) do
        if v:IsEnd() then
            table.insert(ids, k)
        else
            v:OnUpdate()
            if not isPlaying and v:IsPlaying() then
                isPlaying = true
            end
        end
    end
    for k,v in ipairs(ids) do
        local video = self._videos[v]
        self._videos[v] = nil
        video:Dispose()
        if v == self._cameraMovieId then
            self._cameraVideo = nil
        end
    end

    if self._isVideoPlaying ~= isPlaying then
        self._isVideoPlaying = isPlaying
        MgrCenter.SoundMgr:PauseForVideo(isPlaying)
    end
end

function LxMovieMgr:IsVideoPlaying()
    return self._isVideoPlaying
end

function LxMovieMgr:PlayRemoteVideo(url,func,uiTrans,delayPlay)
    self:_InternalPlay(url,func,uiTrans, delayPlay, true)
end

function LxMovieMgr:PlayVideoClipUI(videoName,func,uiTrans, delayPlay)
    self:_InternalPlay(videoName,func,uiTrans, delayPlay, false)
end

function LxMovieMgr:_InternalPlay(videoName,func,uiTrans, delayPlay, isFileUrl)
    local blackTrans = CS.FindTrans(uiTrans,"VideoBlack")
    CS.ShowObject(blackTrans, false)

    local videoTrans = CS.FindTrans(uiTrans, "Video")
    local csRawImg = videoTrans:GetComponent(typeofRawImage)
    if not csRawImg then
        csRawImg = uiTrans.gameObject:AddComponent(typeofRawImage)
        csRawImg.raycastTarget = false
    end

    local delay = delayPlay and 0.4 or 0
    return self:Play({
        url = videoName,
        isFileUrl = isFileUrl,
        executeOk = func,
        delay = delay,
        rawImage = csRawImg,
        loop = false,
        fitHor = false,
        blackTrans = blackTrans,
    })
end

function LxMovieMgr:Play(params)
    if string.isempty(params.url) then
        if LOG_INFO_ENABLED then
            printInfo("movie","movie url is nil ...")
        end
        return
    end
    local camera = nil
    if params.rawImage == nil then
        if self._cameraVideo ~= nil then return end --全局摄像机只能播放一个视频
        camera = self._movieCamera
    end
    local movieId = self:MakeMovieId()
    local video = require("LApp.component.media.LxVideo"):New()
    self._videos[movieId] = video
    if camera ~= nil then
        self._cameraVideo = video
        self._cameraMovieId = movieId
    end
    video:Initialize(movieId, camera , self._movieTrans)
    video:Play(params)
    return movieId
end

function LxMovieMgr:Stop(movieId, executeOk)
    local video = self._videos[movieId]
    if not video then return end

    if video:IsDisposed() or video:IsEnd() then return end

    video:StopPlay(executeOk)
end

---暂停视频
function LxMovieMgr:PauseVideo(movieId)
    if self._isDisposed then return end

    local video = self._videos[movieId]
    if not video then return end

    video:Pause()
end

----继续播放(只对暂停的视频有效)
function LxMovieMgr:ContinueToPlayVideo(movieId)
    local video = self._videos[movieId]
    if not video then return end

    video:Resume()
end

function LxMovieMgr:GetVideoLength(movieId)
    local video = self._videos[movieId]
    if not video then return end

    return video:GetLength()
end

function LxMovieMgr:GetVideoTime(movieId)
    local video = self._videos[movieId]
    if not video then return end

    return video:GetTime()
end

function LxMovieMgr:SetVideoTime(movieId, time)
    local video = self._videos[movieId]
    if not video then return end
    
    video:SetTime(time)
end

return LxMovieMgr